964	  The multiplicative group object $\mathbb G_m = \mathbb A^1 \setminus \{0\}$ described in
965	  \cref{def:genus0_base_objects}, packaged as an object of $\mathrm{Over}\,(\Spec \bar k)$.
966	\end{definition}
967	
968	\begin{definition}
969	[The distinguished $\bar k$-point $0 \in \mathbb P^1$]
970	  \label{def:p1bar_zero}
971	  \lean{AlgebraicGeometry.ProjectiveLineBar.zeroPt}
972	  \uses{def:genus0_base_objects}
973	  % Archon-original Lean encoding (per-decl pin for the $\bar k$-point $0 \in \mathbb P^1$ of
974	  % \cref{def:genus0_base_objects}); no external % SOURCE QUOTE needed.
975	  The $\bar k$-point $0 \in \mathbb P^1(\bar k)$ realised as the morphism
976	  $\Spec \bar k \to \mathbb P^1$ in $\mathrm{Over}\,(\Spec \bar k)$, defined via
977	  $\mathrm{Proj.fromOfGlobalSections}$ on the projective line of \cref{def:genus0_base_objects}.
978	  It is one of the two fixed points of the $\mathbb G_m$-scaling action used in the
979	  primary genus-$0$ proof.
980	\end{definition}
