984	  \label{def:p1bar_one}
985	  \lean{AlgebraicGeometry.ProjectiveLineBar.onePt}
986	  \uses{def:genus0_base_objects}
987	  % Archon-original Lean encoding (per-decl pin for the $\bar k$-point $1 \in \mathbb P^1$ of
988	  % \cref{def:genus0_base_objects}); no external % SOURCE QUOTE needed.
989	  The $\bar k$-point $1 \in \mathbb P^1(\bar k)$ realised as the morphism
990	  $\Spec \bar k \to \mathbb P^1$ in $\mathrm{Over}\,(\Spec \bar k)$, defined via
991	  $\mathrm{Proj.fromOfGlobalSections}$ on the projective line of \cref{def:genus0_base_objects}.
992	\end{definition}
