995	[The distinguished $\bar k$-point $\infty \in \mathbb P^1$]
996	  \label{def:p1bar_infty}
997	  \lean{AlgebraicGeometry.ProjectiveLineBar.inftyPt}
998	  \uses{def:genus0_base_objects}
999	  % Archon-original Lean encoding (per-decl pin for the $\bar k$-point $\infty \in \mathbb P^1$ of
1000	  % \cref{def:genus0_base_objects}); no external % SOURCE QUOTE needed.
1001	  The $\bar k$-point $\infty \in \mathbb P^1(\bar k)$ realised as the morphism
1002	  $\Spec \bar k \to \mathbb P^1$ in $\mathrm{Over}\,(\Spec \bar k)$, defined via
1003	  $\mathrm{Proj.fromOfGlobalSections}$ on the projective line of \cref{def:genus0_base_objects}.
1004	  It is the second fixed point of the $\mathbb G_m$-scaling action.
1005	\end{definition}
