1008	[The multiplicative identity $1 \in \mathbb G_m$]
1009	  \label{def:gm_one}
1010	  \lean{AlgebraicGeometry.Gm.onePt}
1011	  \uses{def:gm}
1012	  % Archon-original Lean encoding (per-decl pin for the unit point of the multiplicative group
1013	  % of \cref{def:genus0_base_objects}); no external % SOURCE QUOTE needed.
1014	  The multiplicative identity $1 \in \mathbb G_m(\bar k)$, supplied in Lean as the unit map
1015	  $\eta[\mathbb G_m] \colon \Spec \bar k \to \mathbb G_m$ in $\mathrm{Over}\,(\Spec \bar k)$.
1016	  It serves as the $W$-base point for the additive decomposition applied in the primary
1017	  $\mathbb G_m$-scaling proof.
1018	\end{definition}
